INSERT INTO `event_analyses` (`id`, `event_id`, `event_name`, `likely_outcome`, `approximate_goals`, `description`, `home_motivation`, `away_motivation`, `home_class`, `away_class`, `influenced_by`, `influenced_by_event_ids`, `created_at`, `updated_at`, `type`, `strength`) VALUES
(19, 51129706998603155, 'St Pauli vs Wolfsburg', 'DRAW', 2, 'Massive relegation six-pointer: St Pauli are 18th, Wolfsburg 16th, and Heidenheim 17th are also on 26 points. All three relegation-zone teams are tied, so both sides are highly motivated but likely cautious. Heidenheim vs Mainz directly influences the survival picture.', 10, 10, 2, 3, '[\"Heidenheim vs Mainz\"]', '[\"851317870018467459\"]', '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(20, 123604100210029914, 'M\'gladbach vs Hoffenheim', 'AWAY_WIN', 3, 'M\'gladbach are safe mid-table with little urgency. Hoffenheim are level with Stuttgart on 61 points and can still fight for the Champions League place, so their motivation is much higher. Stuttgart’s result directly affects Hoffenheim’s final European position.', 2, 8, 4, 7, '[\"Eintracht Frankfurt vs Stuttgart\"]', '[\"595596105163812078\"]', '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(21, 187785962903118086, 'Leverkusen vs Hamburg', 'HOME_WIN', 3, 'Leverkusen are 6th and still close enough to Hoffenheim/Stuttgart to care about final European ranking. Hamburg are 11th with no major pressure. Leverkusen’s motivation is linked to Hoffenheim and Stuttgart results above them.', 7, 2, 7, 4, '[\"M\'gladbach vs Hoffenheim\",\"Eintracht Frankfurt vs Stuttgart\"]', '[\"123604100210029914\",\"595596105163812078\"]', '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(22, 195414499091697526, 'Werder Bremen vs Dortmund', 'AWAY_WIN', 3, 'Werder are 15th, level with Cologne but safely above the 26-point relegation group. Dortmund are 2nd with far superior class and Champions League status. Motivation is not extreme, but Dortmund’s quality gap is large.', 4, 7, 3, 8, NULL, NULL, '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(23, 537909020840964760, 'Freiburg vs RB Leipzig', 'AWAY_WIN', 3, 'Freiburg are 7th, only 1 point ahead of Frankfurt and Augsburg, so they are motivated to protect the Conference League place. RB Leipzig are 3rd and clearly stronger. Frankfurt and Augsburg games influence Freiburg’s European race.', 8, 7, 5, 8, '[\"Eintracht Frankfurt vs Stuttgart\",\"Union Berlin vs Augsburg\"]', '[\"595596105163812078\",\"1152117365672713705\"]', '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(24, 595596105163812078, 'Eintracht Frankfurt vs Stuttgart', 'AWAY_WIN', 3, 'Frankfurt are 8th, only 1 point behind Freiburg, so they still have Conference League motivation. Stuttgart are 4th, level with Hoffenheim, so they need a result to protect Champions League position. Freiburg, Augsburg and Hoffenheim results all influence this game’s stakes.', 7, 8, 5, 8, '[\"Freiburg vs RB Leipzig\",\"Union Berlin vs Augsburg\",\"M\'gladbach vs Hoffenheim\"]', '[\"537909020840964760\",\"1152117365672713705\",\"123604100210029914\"]', '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(25, 779038078341657442, 'Bayern vs Cologne', 'HOME_WIN', 4, 'Bayern are overwhelmingly the strongest side: 117 goals, +82 goal difference, 86 points. Cologne are 14th, level with Werder but safely above the relegation group. Even if Bayern have less urgency, the class gap is huge.', 6, 3, 10, 4, NULL, NULL, '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
(26, 851317870018467459, 'Heidenheim vs Mainz', 'HOME_WIN', 2, 'Heidenheim are 17th, tied with Wolfsburg and St Pauli on 26 points, making this a must-win survival match. Mainz are 10th and safe mid-table. St Pauli vs Wolfsburg directly influences Heidenheim’s survival situation.', 10, 2, 3, 5, '[\"St Pauli vs Wolfsburg\"]', '[\"51129706998603155\"]', '2026-05-16 10:09:04', '2026-05-16 10:09:04', 'GPT_MANUAL', 10),
