(58, 594789860760193405, 'Paris FC vs PSG', 'AWAY_WIN', 3, 'PSG are champions-level leaders with the best class profile in Ligue 1. Paris FC are safe mid-table with little at stake. PSG should win despite limited pressure.', 3, 7, 4, 10, NULL, NULL, '2026-05-17 05:24:36', '2026-05-17 05:24:36', 'GPT_MANUAL', 10),
