(114, 816283885503929978, 'GET_ONE_SAFEST_FOR_EVENT_DEFAULT', 643152929517074290, 12, 'Como is pushing for European qualification with a strong defensive record, making the UNDER 4.5 goals at odds of 1.20 a safe pick against a less motivated Parma.', '2026-05-17 06:08:31', '2026-05-17 06:33:51', 0, NULL),
