(124, 133093590280528384, 'GET_ONE_SAFEST_FOR_EVENT_DEFAULT', 209923074771175965, 8, 'Betting on \'OVER 1.5\' goals at 1.29 odds offers a solid balance between probability and return. Both teams, Levante and Mallorca, are in a relegation battle and will likely play aggressively, seeking goals to boost survival chances.', '2026-05-17 06:11:34', '2026-05-17 06:33:47', 0, NULL),
(125, 156679327416791783, 'GET_ONE_SAFEST_FOR_EVENT_DEFAULT', 444611341263780813, 10, 'Alaves needs a result to avoid potential relegation, while Oviedo is already relegated. Alaves has motivation, making the Draw No Bet on Away a safe choice.', '2026-05-17 06:11:50', '2026-05-17 06:33:47', 0, NULL),
(126, 278172329527356781, 'GET_ONE_SAFEST_FOR_EVENT_DEFAULT', 1059049118248910271, 2, 'The \'DOUBLE_CHANCE 12\' bet offers a good balance of low risk and decent odds at 1.29, covering both teams to win. Villarreal is motivated to secure their Champions League spot and Rayo Vallecano has no strong motivation.', '2026-05-17 06:12:08', '2026-05-17 06:33:47', 0, NULL),
(127, 369024682233724064, 'GET_ONE_SAFEST_FOR_EVENT_DEFAULT', 971222761721757410, 15, 'Atlético Madrid, currently in 4th and vying for a Champions League spot, has strong motivation to secure a positive result. Draw No Bet on Atlético provides safety, and the odds of 1.33 are reasonable for a low-risk return given their higher motivation and form versus lower-ranked Girona.', '2026-05-17 06:12:23', '2026-05-17 06:33:46', 0, NULL),
